            strong_hits += 1

    supportive_hits = 0
    for k in supportive_keywords:
        if k in words:
            supportive_hits += 1

    if strong_hits >= 2: return True
    if strong_hits == 1 and supportive_hits >= 1: return True
    if strong_hits == 0 and supportive_hits >= 3: return True
    return False

